from pydantic_ai import tool, Agent
from contextlib import contextmanager
import time

@contextmanager
def auth_tracer():
    auth_count = 0
    start = time.time()
    try:
        yield auth_count
    finally:
        latency = time.time() - start
        if auth_count > 1:
            print(f'NESTED TOOL LATENCY: {auth_count} auth calls, {latency:.2f}s total')

class TracedAgent(Agent):
    @tool
    async def database_query(self, query: str):
        with auth_tracer() as auth_count:
            # Simulate auth call
            auth_count += 1
            await self.db.connect()
            return await self.db.execute(query)

