from pydantic_ai import Agent, Field
from pydantic import validator

class ProgressiveStreamAgent(Agent):
    response: dict = Field(..., partial=True)  # Allow partial parsing

    @validator('response', pre=True, always=True)
    def progressive_validate(cls, v):
        if isinstance(v, str) and len(v) < 50:  # Early return for short streams
            return {'partial': v}
        return v

    async def stream_optimized(self):
        async for chunk in self.model.stream(prompt):
            partial_result = self.parse_partial(chunk)
            if partial_result:
                yield partial_result
